import { GetSiteInfo, GetSiteDetail } from "@/api/cart"

export default {
    namespaced: true,
    state: {
        activeID: null,

        siteInfo: null,
        siteDetail: null,
    },
    getters: {
        siteInfo: state => {
            if (!state.siteInfo) {
                try {
                    state.siteInfo = JSON.parse(sessionStorage.getItem("HUI_SITE_INFO"))
                } catch {
                    return
                }
            }
            return state.siteInfo
        },
        siteDetail: state => {
            if (!state.siteDetail) {
                try {
                    state.siteDetail = JSON.parse(sessionStorage.getItem("HUI_SITE_DETAIL"))
                } catch {
                    return
                }
            }
            return state.siteDetail
        },
        activeDetail: state => {
            if (state.activeID === null) {
                return null
            }
            console.log(state.siteDetail)
            for (let item of state.siteDetail) {
                console.log(item.id, state.activeID)
                if (item.id === state.activeID) {
                    console.log("here", item)
                    return item
                }
            }
            return null
        }
    },
    mutations: {
        initSiteInfo(state, data) {
            try {
                state.siteInfo = data
                sessionStorage.setItem("HUI_SITE_INFO", JSON.stringify(data))
            } catch {
                console.log("initSiteInfo error")
                return
            }
        },
        initSiteDetail(state, data) {
            try {
                state.siteDetail = data
                sessionStorage.setItem("HUI_SITE_DETAIL", JSON.stringify(data))
            } catch {
                console.log("initSiteDetail error")
                return
            }
        }
    },
    actions: {
        initSiteInfo(ctx) {
            return new Promise((resolve, reject) => {
                GetSiteInfo()
                    .then(data => {
                        ctx.commit("initSiteInfo", data.data)
                        resolve(data)
                    })
                    .catch(err => {
                        reject(err)
                    })
            })
        },
        initSiteDetail(ctx) {
            return new Promise((resolve, reject) => {
                GetSiteDetail()
                    .then(data => {
                        ctx.commit("initSiteDetail", data.data)
                        resolve(data)
                    })
                    .catch(err => {
                        reject(err)
                    })
            })
        },
        activeID(ctx, data) {
            ctx.state.activeID = data
        }
    },
}