const crypto = require("crypto")
const base_config = require("@/configs/base.js")

const SEC_KEY = base_config.SEC_KEY
const SEC_SIGNATURE = base_config.SEC_SIGNATURE
const SEC_SIGNATURE2 = base_config.SEC_SIGNATURE2

export function ValidatorPassword(password) {
    let sig = crypto.createHash("md5").update(`${SEC_KEY}+${password}`).digest("hex")
    if (sig !== SEC_SIGNATURE) {
        return false
    } else {
        return sig
    }
}

export function ValidatorSig(signature) {
    if (!signature) { return false }
    let sig = crypto.createHash("md5").update(`${SEC_KEY}+${signature}`).digest("hex")
    if (sig !== SEC_SIGNATURE2) {
        return false
    } else {
        return sig
    }
}